import React, { createContext, useContext, useState, useEffect } from 'react';
import { db } from './utils/firebase';
import { collection, onSnapshot, addDoc, doc, updateDoc, query, orderBy, serverTimestamp } from 'firebase/firestore';

import UserPortal from './pages/user/UserPortal';
import VendorPortal from './pages/vendor/VendorPortal';
import AdminPortal from './pages/admin/AdminPortal';
import CleanerPortal from './pages/cleaner/CleanerPortal';

const AppContext = createContext();

export const bus = {
  listeners: {},
  on(event, cb) {
    if (!this.listeners[event]) this.listeners[event] = [];
    this.listeners[event].push(cb);
    return () => { this.listeners[event] = this.listeners[event].filter(l => l !== cb); };
  },
  emit(event, data) {
    if (this.listeners[event]) this.listeners[event].forEach(cb => cb(data));
  }
};

export function AppProvider({ children }) {
  const [complaints, setComplaints] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const q = query(collection(db, "complaints"), orderBy("reportedAt", "desc"));
    const unsubscribe = onSnapshot(q, (snapshot) => {
      const liveComplaints = snapshot.docs.map(docSnap => {
        const data = docSnap.data();
        return {
          id: docSnap.id,
          ...data,
          reportedAt: data.reportedAt?.toDate() || new Date(),
          resolvedAt: data.resolvedAt ? data.resolvedAt.toDate() : null
        };
      });
      setComplaints(liveComplaints);
      setLoading(false);
    }, (err) => {
      console.error(err);
      setLoading(false);
    });
    return () => unsubscribe();
  }, []);

  const addComplaint = async (newC) => {
    try {
      const ticketId = `TKT-${String(complaints.length + 1001)}`;
      await addDoc(collection(db, "complaints"), {
        customTicketId: ticketId,
        status: 'NEW',
        reportedAt: serverTimestamp(),
        area: newC.area || 'Platform 1',
        gtype: newC.gtype,
        emoji: newC.emoji || '🗑️',
        severity: newC.severity || 'medium',
        lat: parseFloat(newC.lat),
        lng: parseFloat(newC.lng),
        desc: newC.desc || '',
        reportedBy: newC.reportedBy || 'Citizen',
        station: newC.station,
        vendor: newC.vendor || null,
        cleanerStatus: null,
        assignedTo: null,
        resolutionMins: null,
        resolvedAt: null
      });
    } catch (e) { console.error(e); }
  };

  const updateComplaint = async (docId, fields) => {
    try {
      const docRef = doc(db, "complaints", docId);
      await updateDoc(docRef, fields);
    } catch (e) { console.error(e); }
  };

  return (
    <AppContext.Provider value={{ complaints, addComplaint, updateComplaint, loading }}>
      {children}
    </AppContext.Provider>
  );
}

export function useApp() { return useContext(AppContext); }

export default function App() {
  const [route, setRoute] = useState(window.location.pathname);

  useEffect(() => {
    const handlePopState = () => setRoute(window.location.pathname);
    window.addEventListener('popstate', handlePopState);
    return () => window.removeEventListener('popstate', handlePopState);
  }, []);

  const navigate = (path) => {
    window.history.pushState({}, '', path);
    setRoute(path);
  };

  return (
    <AppProvider>
      <div style={{ position: 'fixed', top: 12, right: 12, zIndex: 9999, display: 'flex', gap: 6, background: 'rgba(10,22,40,0.9)', padding: '6px 10px', borderRadius: 20 }}>
        {['/', '/vendor', '/admin', '/cleaner'].map((p, idx) => {
          const lbl = ['Grievance', 'Vendor', 'Admin', 'Cleaner'][idx];
          return (
            <button key={p} onClick={() => navigate(p)} style={{ background: route === p ? '#1565C0' : 'transparent', color: '#fff', border: 'none', padding: '4px 10px', borderRadius: 12, fontSize: 11, fontWeight: 600, cursor: 'pointer' }}>{lbl}</button>
          )
        })}
      </div>
      <RenderRoute currentPath={route} />
    </AppProvider>
  );
}

function RenderRoute({ currentPath }) {
  const { loading } = useApp();
  if (loading) return <div style={{ display: 'flex', height: '100vh', alignItems: 'center', justifyContent: 'center', fontWeight: 'bold' }}>Syncing with Cloud Firestore Engine...</div>;
  if (currentPath === '/vendor') return <VendorPortal />;
  if (currentPath === '/admin') return <AdminPortal />;
  if (currentPath === '/cleaner') return <CleanerPortal />;
  return <UserPortal />;
}
